mapper.select:
SELECT s.*, c.space_name AS campus_name, (SELECT COUNT(*) FROM space f WHERE f.building_id = s.id AND f.space_type = 'FLOOR' AND f.deleted = 0) AS total_floors FROM space s LEFT JOIN space c ON s.campus_id = c.id WHERE s.space_type = 'BUILDING' AND s.deleted = 0
AND s.building_type = #{buildingType}
AND s.status = #{status}
ORDER BY s.space_code

SELECT s.*, b.building_no AS parent_building_no, f.id AS floor_id, f.space_name AS floor_name, o.unit_name AS org_unit_name, cls.class_name AS class_name, cls.teacher_id AS class_teacher_id, t.real_name AS class_teacher_name, t.phone AS class_teacher_phone FROM space s LEFT JOIN space b ON s.building_id = b.id LEFT JOIN space f ON s.parent_id = f.id AND f.space_type = 'FLOOR' LEFT JOIN org_units o ON s.org_unit_id = o.id LEFT JOIN classes cls ON s.class_id = cls.id LEFT JOIN users t ON cls.teacher_id = t.id WHERE s.building_id = #{buildingId} AND s.space_type = 'ROOM' AND s.deleted = 0
AND s.room_type = #{roomType}
AND s.floor_number = #{floorNumber}
ORDER BY s.floor_number, s.space_code

SELECT s.*, b.space_name AS building_name, b.space_code AS building_code, b.building_no AS parent_building_no, f.id AS floor_id, f.space_name AS floor_name, o.unit_name AS org_unit_name, cls.class_name AS class_name, cls.teacher_id AS class_teacher_id, t.real_name AS class_teacher_name, t.phone AS class_teacher_phone FROM space s LEFT JOIN space b ON s.building_id = b.id LEFT JOIN space f ON s.parent_id = f.id AND f.space_type = 'FLOOR' LEFT JOIN org_units o ON s.org_unit_id = o.id LEFT JOIN classes cls ON s.class_id = cls.id LEFT JOIN users t ON cls.teacher_id = t.id WHERE s.deleted = 0
AND s.space_type = #{spaceType}
AND s.room_type = #{roomType}
AND s.building_type = #{buildingType}
AND s.building_id = #{buildingId}
AND s.floor_number = #{floorNumber}
AND s.org_unit_id = #{orgUnitId}
AND s.status = #{status}
AND (s.space_code LIKE CONCAT('%', #{keyword}, '%') OR s.space_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY s.building_id, s.floor_number, s.space_code LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM space s
WHERE s.deleted = 0

    AND s.space_type = #{spaceType}


    AND s.room_type = #{roomType}


    AND s.building_type = #{buildingType}


    AND s.building_id = #{buildingId}


    AND s.floor_number = #{floorNumber}


    AND s.org_unit_id = #{orgUnitId}


    AND s.status = #{status}


    AND (s.space_code LIKE CONCAT('%', #{keyword}, '%')
         OR s.space_name LIKE CONCAT('%', #{keyword}, '%'))

mapper.update:
UPDATE space
SET current_occupancy = #{occupancy}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM space
WHERE building_no = #{buildingNo}
  AND campus_id = #{campusId}
  AND space_type = 'BUILDING'
  AND deleted = 0

  AND id != #{excludeId}

SELECT COUNT(*)
FROM space
WHERE room_no = #{roomNo}
  AND building_id = #{buildingId}
  AND space_type = 'ROOM'
  AND deleted = 0

  AND id != #{excludeId}
